// // This comment suggests that the parity generator will produce a 1 when the number of 1's in the input data is even.
module parity_generator(
    input [7:0] data,
    output reg parity
);

always @(*) begin
    parity = data[0] ^ data[1] ^ data[2] ^ data[3] ^ data[4] ^ data[5] ^ data[6] ^ data[7];
end

endmodule
